import _ from 'lodash';

// 先んじてprocess.envの直読み込みをしないと正常に取れない（関数経由などもできない）
const PROCESS_ENV_MAPPING: { [key: string]: string | undefined } = {
  // .envの情報
  APP_ENV: process.env['NEXT_PUBLIC_APP_ENV'],
  API_HOST: process.env['NEXT_PUBLIC_API_HOST'],
  WEB_HOST: process.env['NEXT_PUBLIC_WEB_HOST'],
  NEXT_PUBLIC_MAINTENANCE_FILE_URL:
    process.env['NEXT_PUBLIC_NEXT_PUBLIC_MAINTENANCE_FILE_URL'],
  LOCAL_STORAGE_KEY: process.env['NEXT_PUBLIC_LOCAL_STORAGE_KEY'],
  LOG_LEVEL: process.env['NEXT_PUBLIC_LOG_LEVEL'],
  NEXT_PUBLIC_APP_UPDATED_AT: process.env['NEXT_PUBLIC_APP_UPDATED_AT'],
  NEXT_PUBLIC_GIT_COMMIT_HASH: process.env['NEXT_PUBLIC_GIT_COMMIT_HASH'],
  COGNITO_ENDPOINT: process.env['NEXT_PUBLIC_COGNITO_ENDPOINT'],
  COGNITO_POOL_ID: process.env['NEXT_PUBLIC_COGNITO_POOL_ID'],
  COGNITO_POOL_CLIENT_ID: process.env['NEXT_PUBLIC_COGNITO_POOL_CLIENT_ID'],
  ENABLE_PRODUCTION_REDIRECT:
    process.env['NEXT_PUBLIC_ENABLE_PRODUCTION_REDIRECT'],
  STRIPE_PUBLISHABLE_KEY: process.env['NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY'],
  STRIPE_PRICING_TABLE_ID: process.env['NEXT_PUBLIC_STRIPE_PRICING_TABLE_ID'],

  // reactの環境変数
  ENABLE_REDUX_DEV_TOOLS: process.env['REACT_APP_ENABLE_REDUX_DEV_TOOLS'],
};

/**
 * 環境変数を元とする情報の型付けと管理
 * process.envでのアクセスだと型変換が必要だったり、そもそも設定されているかのチェックや変更に関して弱かったりするので、こちらでまとめて型定義など行う
 */
export class EnvManager {
  private _config;
  private static singleton: EnvManager;

  constructor() {
    const fixBooleanStr = (x: string) => x == '1' || x == 'true';
    this._config = {
      APP_ENV: this.getOrShowError<
        'production' | 'staging' | 'develop' | 'local' | 'test'
      >('APP_ENV')!,
      API_HOST: this.getOrShowError<string>('API_HOST')!,
      WEB_HOST: this.getOrShowError<string>('WEB_HOST')!,
      NEXT_PUBLIC_MAINTENANCE_FILE_URL: this.getOrShowError<string>(
        'NEXT_PUBLIC_MAINTENANCE_FILE_URL',
      )!,
      LOCAL_STORAGE_KEY: this.getOrShowError<string>('LOCAL_STORAGE_KEY')!,
      LOG_LEVEL: this.getOrShowError<number>('LOG_LEVEL', {
        default: 0,
        cast: _.toNumber,
      })!,
      APP_UPDATED_AT: this.getOrShowError<string>(
        'NEXT_PUBLIC_APP_UPDATED_AT',
      )!,
      GIT_COMMIT_HASH: this.getOrShowError<string>(
        'NEXT_PUBLIC_GIT_COMMIT_HASH',
      )!,
      COGNITO_ENDPOINT: this.getOrShowError<string>('COGNITO_ENDPOINT', {
        default: '',
      })!,
      COGNITO_POOL_ID: this.getOrShowError<string>('COGNITO_POOL_ID')!,
      COGNITO_POOL_CLIENT_ID: this.getOrShowError<string>(
        'COGNITO_POOL_CLIENT_ID',
      )!,
      ENABLE_PRODUCTION_REDIRECT: this.getOrShowError<boolean>(
        'ENABLE_PRODUCTION_REDIRECT',
        {
          cast: fixBooleanStr,
          default: false,
        },
      ),

      STRIPE_PUBLISHABLE_KEY: this.getOrShowError<string>(
        'STRIPE_PUBLISHABLE_KEY',
      )!,
      STRIPE_PRICING_TABLE_ID: this.getOrShowError<string>(
        'STRIPE_PRICING_TABLE_ID',
      )!,

      ENABLE_REDUX_DEV_TOOLS: this.getOrShowError<boolean>(
        'ENABLE_REDUX_DEV_TOOLS',
        {
          cast: fixBooleanStr,
          default: false,
        },
      )!,
    };
  }

  static get config() {
    if (!this.singleton) {
      this.singleton = new EnvManager();
    }
    return this.singleton._config;
  }

  /**
   * 環境判定用の定数
   */
  static get isLocal(): boolean {
    return this.config.APP_ENV === 'local';
  }

  static get isDev(): boolean {
    return this.config.APP_ENV === 'develop';
  }

  static get isStg(): boolean {
    return this.config.APP_ENV === 'staging';
  }

  static get isPrd(): boolean {
    return this.config.APP_ENV === 'production';
  }

  static get isTest(): boolean {
    return this.config.APP_ENV === 'test';
  }

  private getOrShowError<T>(
    key: any,
    opts: { default?: any; cast?: ((v: string) => T) | null } = {
      default: undefined,
      cast: null,
    },
  ): T | null {
    const val = PROCESS_ENV_MAPPING[key];
    if (val) {
      // undefinedや空文字の場合は含まれない
      if (opts.cast) {
        return opts.cast(val);
      }
      return val as T;
    } else if (opts.default !== undefined && _.has(PROCESS_ENV_MAPPING, key)) {
      // 中身が空でdefaultが設定されているものについてはdefaultを返す
      return opts.default;
    }
    // そもそもkeyが.envに設定されていないケースか、あるいはキーが設定されているもののdefaultが設定されておらず中身が空の場合
    // loggerとの循環参照になるのでこっちはconsoleを使う
    // eslint-disable-next-line no-console
    console.error(
      `Insufficient environment value for key: ${key}. Check your .env`,
    );
    return null;
  }
}

